import 'package:equatable/equatable.dart'; class UserEntity extends Equatable { final String uid; final String email; final String? displayName; final String? photoUrl; final bool emailVerified; final String? phone; final DateTime? createdAt; final bool isActive; final String? fcmToken; const UserEntity({required this.uid, required this.email, this.displayName, this.photoUrl, this.emailVerified = false, this.phone, this.createdAt, this.isActive = true, this.fcmToken}); @override List<Object?> get props => [uid, email]; String get initials { if (displayName == null || displayName!.isEmpty) return email[0].toUpperCase(); final p = displayName!.trim().split(' '); return p.length >= 2 ? '${p[0][0]}${p[1][0]}'.toUpperCase() : p[0][0].toUpperCase(); } }
